args.sparql:
SELECT ?gameFranchise ?gameLabel WHERE {
  ?gameFranchise wdt:P178 wd:Q149947 .
  ?gameFranchise wdt:P31 wd:Q241163 .
  ?movie wdt:P144 ?gameFranchise .
  ?movie wdt:P31 wd:Q11424 .
  ?movie wdt:P577 ?date .
  FILTER(YEAR(?date) = 1995)
  OPTIONAL { ?gameFranchise rdfs:label ?gameLabel FILTER(LANG(?gameLabel) = "en") }
}

SELECT ?franchise ?franchiseLabel WHERE {
  ?game wdt:P178 wd:Q149947 ;
        wdt:P179 ?franchise .
  ?movie wdt:P144 ?game ;
         wdt:P31 wd:Q11424 ;
         wdt:P577 ?date .
  FILTER(YEAR(?date) = 1995)
  ?franchise rdfs:label ?franchiseLabel .
  FILTER(LANG(?franchiseLabel) = 'en')
}
